     1→import type { StateCreator } from 'zustand';
     2→import {
     3→  PointsBalanceStatus,
     4→  PointsExtractStatus,
     5→  type AppliedFilters,
     6→  type ExpiringFilters,
     7→  type PointsBalanceState,
     8→  type PointsExtractData,
     9→  type PointsExtractFiltersState,
    10→  type PointsExtractState,
    11→  type ProcessedExtractData,
    12→} from '../models';
    13→
    14→export interface PointsExtractActions {
    15→  setExtractStatus: (status: PointsExtractStatus) => void;
    16→  setExtractData: (
    17→    extractData: PointsExtractData,
    18→    processedExtractData?: ProcessedExtractData,
    19→  ) => void;
    20→  appendExtractData: (
    21→    extractData: PointsExtractData,
    22→    processedExtractData?: ProcessedExtractData,
    23→  ) => void;
    24→  setLoadingMore: (isLoading: boolean) => void;
    25→  setBalanceStatus: (status: PointsBalanceStatus) => void;
    26→  setBalance: (points?: number) => void;
    27→  setTransactionsFilters: (filters: AppliedFilters) => void;
    28→  clearTransactionsFilters: () => void;
    29→  setExpiringFilters: (filters: ExpiringFilters) => void;
    30→  clearExpiringFilters: () => void;
    31→  reset: () => void;
    32→}
    33→
    34→export interface PointsExtractSlice {
    35→  pointsExtract: PointsExtractState;
    36→  pointsBalance: PointsBalanceState;
    37→  pointsExtractFilters: PointsExtractFiltersState;
    38→  pointsExtractActions: PointsExtractActions;
    39→}
    40→
    41→const INITIAL_POINTS_EXTRACT_STATE: PointsExtractState = {
    42→  extractData: undefined,
    43→  processedExtractData: undefined,
    44→  status: PointsExtractStatus.IDLE,
    45→  isLoadingMore: false,
    46→  error: undefined,
    47→};
    48→
    49→const INITIAL_POINTS_BALANCE_STATE: PointsBalanceState = {
    50→  points: undefined,
    51→  status: PointsBalanceStatus.IDLE,
    52→  error: undefined,
    53→};
    54→
    55→const INITIAL_POINTS_EXTRACT_FILTERS_STATE: PointsExtractFiltersState = {
    56→  appliedTransactionsFilters: undefined,
    57→  appliedExpiringFilters: undefined,
    58→};
    59→
    60→export const createPointsExtractSlice: StateCreator<
    61→  PointsExtractSlice,
    62→  [],
    63→  [],
    64→  PointsExtractSlice
    65→> = set => ({
    66→  pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
    67→  pointsBalance: INITIAL_POINTS_BALANCE_STATE,
    68→  pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
    69→  pointsExtractActions: {
    70→    setExtractStatus: status =>
    71→      set(state => ({
    72→        pointsExtract: {
    73→          ...state.pointsExtract,
    74→          status,
    75→          ...(status === PointsExtractStatus.IDLE ||
    76→          status === PointsExtractStatus.LOADING
    77→            ? { error: undefined }
    78→            : {}),
    79→        },
    80→      })),
    81→    setExtractData: (extractData, processedExtractData) =>
    82→      set(state => ({
    83→        pointsExtract: {
    84→          ...state.pointsExtract,
    85→          extractData,
    86→          processedExtractData,
    87→          status: PointsExtractStatus.SUCCESS,
    88→          isLoadingMore: false,
    89→          error: undefined,
    90→        },
    91→      })),
    92→    appendExtractData: (extractData, processedExtractData) =>
    93→      set(state => {
    94→        const existingTransactions =
    95→          state.pointsExtract.extractData?.transactions ?? [];
    96→        const newTransactions = extractData.transactions;
    97→        const mergedTransactions = [
    98→          ...existingTransactions,
    99→          ...newTransactions,
   100→        ];
   101→
   102→        const existingProcessed = state.pointsExtract.processedExtractData;
   103→        const newProcessed = processedExtractData;
   104→
   105→        let mergedProcessed: ProcessedExtractData | undefined;
   106→        if (existingProcessed && newProcessed) {
   107→          const existingMapped = existingProcessed.mappedTransactions ?? [];
   108→          const newMapped = newProcessed.mappedTransactions ?? [];
   109→          mergedProcessed = {
   110→            groupedTransactions: newProcessed.groupedTransactions,
   111→            mappedTransactions: [
   112→              ...existingMapped,
   113→              ...newMapped,
   114→            ],
   115→          };
   116→        } else {
   117→          mergedProcessed = newProcessed ?? existingProcessed;
   118→        }
   119→
   120→        return {
   121→          pointsExtract: {
   122→            ...state.pointsExtract,
   123→            extractData: {
   124→              transactions: mergedTransactions,
   125→              pagination: extractData.pagination,
   126→            },
   127→            processedExtractData: mergedProcessed,
   128→            isLoadingMore: false,
   129→          },
   130→        };
   131→      }),
   132→    setLoadingMore: isLoading =>
   133→      set(state => ({
   134→        pointsExtract: {
   135→          ...state.pointsExtract,
   136→          isLoadingMore: isLoading,
   137→        },
   138→      })),
   139→    setBalanceStatus: status =>
   140→      set(state => ({
   141→        pointsBalance: {
   142→          ...state.pointsBalance,
   143→          status,
   144→        },
   145→      })),
   146→    setBalance: points =>
   147→      set(state => ({
   148→        pointsBalance: {
   149→          ...state.pointsBalance,
   150→          points,
   151→          status: PointsBalanceStatus.SUCCESS,
   152→          error: undefined,
   153→        },
   154→      })),
   155→    setTransactionsFilters: filters =>
   156→      set(state => ({
   157→        pointsExtractFilters: {
   158→          ...state.pointsExtractFilters,
   159→          appliedTransactionsFilters: filters,
   160→        },
   161→      })),
   162→    clearTransactionsFilters: () =>
   163→      set(state => ({
   164→        pointsExtractFilters: {
   165→          ...state.pointsExtractFilters,
   166→          appliedTransactionsFilters: undefined,
   167→        },
   168→      })),
   169→    setExpiringFilters: filters =>
   170→      set(state => ({
   171→        pointsExtractFilters: {
   172→          ...state.pointsExtractFilters,
   173→          appliedExpiringFilters: filters,
   174→        },
   175→      })),
   176→    clearExpiringFilters: () =>
   177→      set(state => ({
   178→        pointsExtractFilters: {
   179→          ...state.pointsExtractFilters,
   180→          appliedExpiringFilters: undefined,
   181→        },
   182→      })),
   183→    reset: () =>
   184→      set({
   185→        pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
   186→        pointsBalance: INITIAL_POINTS_BALANCE_STATE,
   187→        pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
   188→      }),
   189→  },
   190→});
